import{c as a,Q as e,j as o,m as r}from"./chunks/framework.DpF7k2f3.js";const _=JSON.parse('{"title":"제7장 AI 에이전트 핵심 로직","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part2-fundamentals/chapter7.md","filePath":"ko/part2-fundamentals/chapter7.md","lastUpdated":1779671667000}'),n={name:"ko/part2-fundamentals/chapter7.md"};function p(s,t,l,i,u,c){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="제7장-ai-에이전트-핵심-로직" tabindex="-1">제7장 AI 에이전트 핵심 로직 <a class="header-anchor" href="#제7장-ai-에이전트-핵심-로직" aria-label="Permalink to &quot;제7장 AI 에이전트 핵심 로직&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>기초편의 마지막 챕터에 오신 것을 축하합니다!</p><p>앞의 챕터들이 &quot;AI使用方法&quot;를 가르쳤다면, 이 챕터는 &quot;AI가 혼자 일하게 하는 방법&quot;을 가르칩니다.</p><p>먼저 질문합니다: 대규모 모델과 AI 에이전트의 핵심 차이는 무엇입니까?</p><p>대규모 모델은 受动的 - 물으면 답하고, 한 질문에 한 답, 천장이 낮습니다. AI 에이전트는 主动的 - 목표를 주면, 스스로 방법을 찾고, 자료를查找하고, 도구를 호출하고, 결과를 검증하며, 작업이 완료될 때까지 계속합니다.</p><p>&quot;告诉我怎么做&quot;에서 &quot;你自己看着办&quot;로, 이것은 질적 도약입니다.</p><p>이 챕터를 읽고 나면 가져갈 것들:</p><ul><li><strong>에이전트의 본질 이해</strong>: 왜 에이전트가 AI 앱의 미래인지</li><li><strong>에이전트 아키텍처 전체 보기</strong>: 인식, 추론, 행동, 기억의 네 가지 주요 구성 요소</li><li><strong>도구 호출 능력</strong>: AI가 реальный 세계를 조작할 수 있게 함(프로덕션급 코드 포함)</li><li><strong>계획 및 추론 패턴</strong>: ReAct 완전한 추적, LangGraph 2026 실전, Plan-and-Execute</li><li><strong>멀티 에이전트 협업</strong>: 두 개의 실제 사용 가능한 사례</li><li><strong>에이전트 신뢰성 엔지니어링</strong>: 실패의 6가지 패턴, 비용 제어, 출력 검증</li></ul><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter7.html">中文版阅读</a></p></blockquote>',11)])])}const h=a(n,[["render",p]]);export{_ as __pageData,h as default};
